from haystack import component, Document
from haystack.core.component.types import Variadic
from typing import List, Optional
from vex_sdk import Vex, CheckResult
import logging

logger = logging.getLogger(__name__)

@component
class VexRetrievalGuardrail:
    """
    A Haystack component that validates retriever output using Vex
    before passing documents to the PromptBuilder.
    """

    def __init__(self, vex_client: Vex, min_relevance_score: float = 0.5, pipeline_name: str = 'haystack-rag'):
        self.vex = vex_client
        self.min_relevance_score = min_relevance_score
        self.pipeline_name = pipeline_name

    @component.output_types(
        documents=List[Document],
        filtered_count=int,
        guardrail_passed=bool
    )
    def run(self, documents: List[Document], query: str) -> dict:
        if not documents:
            logger.warning('VexGuardrail: No documents received from retriever')
            # Report empty retrieval to Vex
            self.vex.report_event(
                pipeline=self.pipeline_name,
                event_type='empty_retrieval',
                metadata={'query': query, 'document_count': 0}
            )
            return {'documents': [], 'filtered_count': 0, 'guardrail_passed': False}

        # Run Vex reliability check on retrieved documents
        check_result: CheckResult = self.vex.check(
            pipeline=self.pipeline_name,
            step='retrieval_validation',
            inputs={
                'query': query,
                'documents': [{'content': doc.content, 'score': doc.score} for doc in documents]
            },
            checks=[
                {'type': 'retrieval_relevance', 'threshold': self.min_relevance_score},
                {'type': 'document_count', 'min': 1}
            ]
        )

        # Filter documents below relevance threshold
        filtered_docs = [
            doc for doc in documents
            if doc.score is None or doc.score >= self.min_relevance_score
        ]

        if not check_result.passed:
            logger.error(f'VexGuardrail: Retrieval check failed — {check_result.reason}')

        return {
            'documents': filtered_docs,
            'filtered_count': len(documents) - len(filtered_docs),
            'guardrail_passed': check_result.passed
        }

from haystack import component, Document
from typing import List
from vex_sdk import Vex
import logging

logger = logging.getLogger(__name__)

@component
class VexFaithfulnessGuardrail:
    """
    Post-generation component that checks if the LLM answer
    is grounded in the retrieved documents using Vex.
    """

    def __init__(self, vex_client: Vex, pipeline_name: str = 'haystack-rag', block_on_failure: bool = False):
        self.vex = vex_client
        self.pipeline_name = pipeline_name
        self.block_on_failure = block_on_failure

    @component.output_types(
        replies=List[str],
        faithfulness_score=float,
        is_faithful=bool
    )
    def run(self, replies: List[str], documents: List[Document], query: str) -> dict:
        answer = replies[0] if replies else ''
        context = ' '.join([doc.content for doc in documents if doc.content])

        # Run Vex faithfulness check
        check_result = self.vex.check(
            pipeline=self.pipeline_name,
            step='faithfulness_validation',
            inputs={
                'query': query,
                'answer': answer,
                'context': context
            },
            checks=[
                {'type': 'faithfulness', 'threshold': 0.7},
                {'type': 'no_hallucination'}
            ]
        )

        faithfulness_score = check_result.scores.get('faithfulness', 1.0)
        is_faithful = check_result.passed

        if not is_faithful:
            logger.warning(
                f'VexGuardrail: Faithfulness check failed. Score: {faithfulness_score:.2f}. '
                f'Reason: {check_result.reason}'
            )
            self.vex.report_event(
                pipeline=self.pipeline_name,
                event_type='hallucination_detected',
                metadata={
                    'query': query,
                    'answer': answer,
                    'faithfulness_score': faithfulness_score
                }
            )
            if self.block_on_failure:
                fallback = 'I could not find a reliable answer based on the available documents.'
                return {'replies': [fallback], 'faithfulness_score': faithfulness_score, 'is_faithful': False}

        return {'replies': replies, 'faithfulness_score': faithfulness_score, 'is_faithful': is_faithful}
